package com.example.bookservice.controller;import com.example.bookservice.exception.ExceptionController;import com.example.bookservice.model.Book;import com.example.bookservice.model.BookAdminStatsDto;import com.example.bookservice.model.BookDto;import com.example.bookservice.service.BookService;import com.fasterxml.jackson.databind.ObjectMapper;import org.junit.jupiter.api.BeforeEach;import org.junit.jupiter.api.Test;import org.junit.jupiter.api.extension.ExtendWith;import org.mockito.InjectMocks;import org.mockito.Mock;import org.mockito.junit.jupiter.MockitoExtension;import org.springframework.http.MediaType;import org.springframework.test.web.servlet.MockMvc;import org.springframework.test.web.servlet.setup.MockMvcBuilders;import java.util.Arrays;import java.util.Collections;import java.util.List;import static org.mockito.ArgumentMatchers.any;import static org.mockito.Mockito.doNothing;import static org.mockito.Mockito.when;import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;@ExtendWith(MockitoExtension.class)class BookControllerTest {  private MockMvc mockMvc;  private ObjectMapper objectMapper;  @Mock private BookService bookService;  @InjectMocks private BookController bookController;  private BookDto bookDto;  private Book book;  @BeforeEach  void setUp() {    objectMapper = new ObjectMapper();    mockMvc =        MockMvcBuilders.standaloneSetup(bookController)            .setControllerAdvice(new ExceptionController())            .build();    bookDto = new BookDto("owner1", "Книга", "Автор", "Жанр", "Описание");    book = new Book();    book.setId(1L);    book.setName("Книга");    book.setAuthor("Автор");    book.setGenre("Жанр");    book.setDescription("Описание");    book.setOwners(Collections.singletonList("owner1"));  }  @Test  void createBook_ReturnCreated() throws Exception {    doNothing().when(bookService).addBookOnSite(any(BookDto.class));    mockMvc        .perform(            post("/books")                .contentType(MediaType.APPLICATION_JSON)                .content(objectMapper.writeValueAsString(bookDto)))        .andExpect(status().isCreated());  }  @Test  void addBookForUser_ReturnCreated() throws Exception {    doNothing().when(bookService).addBookOnProfile(any(BookDto.class));    mockMvc        .perform(            post("/books/append")                .contentType(MediaType.APPLICATION_JSON)                .content(objectMapper.writeValueAsString(bookDto)))        .andExpect(status().isCreated());  }  @Test  void getBooksByLogin_ReturnListOfBooks() throws Exception {    List<Book> books = Collections.singletonList(book);    when(bookService.getBooksByReady()).thenReturn(books);    mockMvc        .perform(get("/books/top"))        .andExpect(status().isOk())        .andExpect(jsonPath("$[0].id").value(1L))        .andExpect(jsonPath("$[0].name").value("Книга"))        .andExpect(jsonPath("$[0].author").value("Автор"))        .andExpect(jsonPath("$[0].genre").value("Жанр"))        .andExpect(jsonPath("$[0].description").value("Описание"))        .andExpect(jsonPath("$[0].owners[0]").value("owner1"));  }  @Test  void getBookById_ReturnBook() throws Exception {    when(bookService.getBooksById(1L)).thenReturn(book);    mockMvc        .perform(get("/books/1"))        .andExpect(status().isOk())        .andExpect(jsonPath("$.id").value(1L))        .andExpect(jsonPath("$.name").value("Книга"));  }  @Test  void getBooksByOwner_ReturnListOfBooks() throws Exception {    List<Book> books = Collections.singletonList(book);    when(bookService.getBooksByOwner("owner1")).thenReturn(books);    mockMvc        .perform(get("/books/user/owner1"))        .andExpect(status().isOk())        .andExpect(jsonPath("$[0].id").value(1L))        .andExpect(jsonPath("$[0].name").value("Книга"));  }  @Test  void getOwnersByBook_ReturnListOfOwners() throws Exception {    List<String> owners = Arrays.asList("owner1", "owner2");    when(bookService.getOwnersLoginById(1L)).thenReturn(owners);    mockMvc        .perform(get("/books/owners/1"))        .andExpect(status().isOk())        .andExpect(jsonPath("$[0]").value("owner1"))        .andExpect(jsonPath("$[1]").value("owner2"));  }  @Test  void getBookAdminStats_ReturnStats() throws Exception {    BookAdminStatsDto statsDto = new BookAdminStatsDto(10L, 5L, 50);    when(bookService.getBookStatsForAdmin()).thenReturn(statsDto);    mockMvc        .perform(get("/books/stats"))        .andExpect(status().isOk())        .andExpect(jsonPath("$.countBooks").value(10L))        .andExpect(jsonPath("$.countReadyBooks").value(5L))        .andExpect(jsonPath("$.percentReady").value(50));  }  @Test  void deleteBooks_ReturnNoContent() throws Exception {    doNothing().when(bookService).deleteOwner(any(BookDto.class));    mockMvc        .perform(            put("/books/delete")                .contentType(MediaType.APPLICATION_JSON)                .content(objectMapper.writeValueAsString(bookDto)))        .andExpect(status().isNoContent());  }}